// store previous values (persistent)
let prev = context.get("prevVitals") || {
    heartRate: 80,
    spo2: 96,
    temperature: 36.8
};

// helper to slightly change value
function vary(value, minChange, maxChange) {
    let change = (Math.random() * (maxChange - minChange)) + minChange;
    return value + change;
}

// ✅ gradual realistic change
let heartRate = Math.round(vary(prev.heartRate, -3, 3));
let spo2 = Math.round(vary(prev.spo2, -1, 1));
let temperature = parseFloat(vary(prev.temperature, -0.2, 0.2).toFixed(1));

// 🔥 DANGER MODE (progressive deterioration)
let dangerMode = context.get("dangerMode") || false;

if (Math.random() < 0.05) {
    dangerMode = true;
}

if (dangerMode) {
    spo2 = Math.max(spo2 - 2, 80);
    heartRate = Math.min(heartRate + 5, 140);
}

// clamp realistic limits
heartRate = Math.min(Math.max(heartRate, 60), 130);
spo2 = Math.min(Math.max(spo2, 85), 100);
temperature = Math.min(Math.max(temperature, 35.5), 39);

// 🔥 occasional anomaly (controlled spikes)
if (Math.random() < 0.1) {
    spo2 = Math.max(spo2 - 5, 80);
}
if (Math.random() < 0.08) {
    heartRate = Math.min(heartRate + 20, 140);
}
if (Math.random() < 0.05) {
    temperature = Math.min(temperature + 1.5, 40);
}

// save state
context.set("prevVitals", { heartRate, spo2, temperature });
context.set("dangerMode", dangerMode);

// output
msg.payload = {
    patientId: "ELD001",
    deviceId: "SIM001",
    heartRate,
    spo2,
    temperature,
    timestamp: new Date().toISOString()
};

msg.headers = {
    "Content-Type": "application/json"
};

return msg;
